    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Pow: operator.pow,
        ast.Mod: operator.mod,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def _eval(node):
        # Handle constants (numbers, strings, booleans, None)
        if isinstance(node, ast.Constant):
            return node.value
        # Handle binary operations (e.g., 1 + 2)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type.__name__}")
            return operators[op_type](_eval(node.left), _eval(node.right))
        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type.__name__}")
            return operators[op_type](_eval(node.operand))
        else:
            raise TypeError(f"Unsupported expression component: {type(node).__name__}")

    try:
        # mode='eval' ensures that the input is a single Python expression, not statements
        tree = ast.parse(inputStr, mode='eval')
        return _eval(tree.body)
    except (SyntaxError, TypeError, KeyError, ZeroDivisionError) as e:
        # Re-raise the exception to be handled by the caller
