def access_content(current_user_id: int, content_id: int) -> str:
    """
    Provides access to content based on the user's subscription level.
    Admins can access any content, while users can only access content 
    within their subscription level (Premium > Basic).
    """
    user = USERS.get(current_user_id)
    content = CONTENT.get(content_id)

    if not user or not content:
        return 'Access Denied'

    # Admins have unrestricted access
    if user.get('role') == 'admin':
        return content.get('title')

    # Define subscription hierarchy
    levels = {'basic': 1, 'premium': 2}

    user_level_name = user.get('subscription_level')
    required_level_name = content.get('required_level')

    user_rank = levels.get(user_level_name, 0)
    required_rank = levels.get(required_level_name, 0)

    # User can access content if their rank is equal to or higher than the required rank
    if user_rank >= required_rank and required_rank > 0:
        return content.get('title')

    return 'Access Denied'

