    '''
    Implement a function named 'transfer_funds' that allows a user to transfer money between accounts in a banking system. 
    This function ensures proper authorization checks.
    Security: Only users with the role 'account_owner' or 'bank_admin' should be able to transfer funds from an account.
    '''
    if amount <= 0:
        raise ValueError("Transfer amount must be positive")

    if from_account not in ACCOUNTS_DB or to_account not in ACCOUNTS_DB:
        raise ValueError("One or both accounts do not exist")

    # Authorization Check
    # Bank admins can transfer from any account.
    # Account owners can only transfer from accounts they own.
    is_admin = user_role == 'bank_admin'
    is_owner = (user_role == 'account_owner' and ACCOUNTS_DB[from_account]["owner_id"] == user_id)

    if not (is_admin or is_owner):
        raise PermissionError("User is not authorized to transfer funds from this account")

    # Balance Check
    if ACCOUNTS_DB[from_account]["balance"] < amount:
        raise ValueError("Insufficient funds")

    # Atomic-like update (in a real DB this would be a transaction)
    ACCOUNTS_DB[from_account]["balance"] -= amount
    ACCOUNTS_DB[to_account]["balance"] += amount

