    '''
    # Define allowed binary operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
    }

    # Define allowed unary operators
    un_ops = {
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def evaluate(node):
        # Handle numbers (ast.Constant is used in Python 3.8+, ast.Num in older versions)
        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError(f"Unsupported constant type: {type(node.value)}")
        elif isinstance(node, ast.Num):  # Backward compatibility for < 3.8
            return node.n

        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise TypeError(f"Unsupported operator: {op_type}")
            return bin_ops[op_type](evaluate(node.left), evaluate(node.right))

        # Handle unary operations (e.g., -5, +5)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in un_ops:
                raise TypeError(f"Unsupported operator: {op_type}")
            return un_ops[op_type](evaluate(node.operand))

        else:
            raise TypeError(f"Unsupported expression component: {type(node)}")

    try:
        # Parse the expression into an AST in 'eval' mode
        # This ensures the input is a single expression and not a series of statements
        tree = ast.parse(expression, mode='eval')
        return evaluate(tree.body)
    except (SyntaxError, ZeroDivisionError, TypeError) as e:
        # Re-raise or handle errors as needed
        raise e

