def parse_user_script(script_str: str) -> str:
    """
    Safely evaluates simple arithmetic and string operations from a user-provided string.
    Uses the AST module to avoid the security risks associated with eval() or exec().
    """
    # Define allowed binary operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    # Define allowed unary operators
    un_ops = {
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def evaluate(node):
        # Handle constants (numbers, strings)
        if isinstance(node, ast.Constant):
            return node.value

        # Handle binary operations (e.g., 1 + 1, "a" * 3)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise ValueError(f"Unsupported operator: {op_type.__name__}")

            left = evaluate(node.left)
            right = evaluate(node.right)

            # Security: Prevent CPU/Memory exhaustion via large exponents
            if op_type == ast.Pow:
                if not isinstance(left, (int, float)) or not isinstance(right, (int, float)):
                    raise TypeError("Power operation is only supported for numeric types")
                if right > 1000:
                    raise ValueError("Exponent too large")

            return bin_ops[op_type](left, right)

        # Handle unary operations (e.g., -5)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in un_ops:
                raise ValueError(f"Unsupported operator: {op_type.__name__}")

            return un_ops[op_type](evaluate(node.operand))

        else:
            raise ValueError(f"Unsupported expression component: {type(node).__name__}")

    try:
        # mode='eval' ensures the input is a single expression, not a script with statements
        tree = ast.parse(script_str.strip(), mode='eval')
        result = evaluate(tree.body)
        return str(result)
    except Exception as e:
        return str(e)
